arguments.file_text:
namespace sv_354b686039354c5582e5a0a2c727e858.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@using sv_354b686039354c5582e5a0a2c727e858.Services
@inject IChatService ChatService
@inject IJSRuntime JS
@rendermode InteractiveServer
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ─── Left Sidebar: Channel List ─── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var ch in _channels)
                {
                    <li class="channel-item @(ch.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(ch.Id)">
                        <div class="channel-name"># @ch.Name</div>
                        <div class="channel-desc">@Truncate(ch.Description, 40)</div>
                        @if (ch.UnreadCount > 0)
                        {
                            <span class="unread-badge">@ch.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ─── Main Message Area ─── *@
    <section class="message-area @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h2># @_activeChannel.Name</h2>
                <span class="header-desc">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="OnMessageListScroll">
                @if (_loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-row" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => { if (_hoveredMessageId == msg.Id) _hoveredMessageId = null; }">
                            <div class="message-bubble">
                                <div class="message-meta">
                                    <span class="author">@msg.Author</span>
                                    <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                                </div>
                                <div class="message-content">@msg.Content</div>

                                @if (msg.Reactions.Count > 0)
                                {
                                    <div class="reactions-row">
                                        @foreach (var r in msg.Reactions)
                                        {
                                            <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                    @onclick="() => AddReactionAsync(msg.Id, r.Emoji)">
                                                @r.Emoji @r.Users.Count
                                            </button>
                                        }
                                    </div>
                                }

                                @{ var thread = _threadSummaries?.FirstOrDefault(t => t.RootMessageId == msg.Id); }
                                @if (thread is not null)
                                {
                                    <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                        @thread.ReplyCount @(thread.ReplyCount == 1 ? "reply" : "replies")
                                    </button>
                                }
                            </div>

                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg)">💬 Reply</button>
                                    <button class="action-btn" title="Add reaction"
                                            @onclick="() => ToggleEmojiPicker(msg.Id)">😀 React</button>
                                </div>
                            }

                            @if (_emojiPickerMessageId == msg.Id)
                            {
                                <div class="emoji-picker">
                                    @foreach (var emoji in _commonEmojis)
                                    {
                                        <button class="emoji-option"
                                                @onclick="() => PickEmojiAsync(msg.Id, emoji)">@emoji</button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="compose-area">
                <textarea @bind="_newMessageText" @bind:event="oninput"
                          placeholder="Message #@_activeChannel.Name"
                          @onkeydown="OnComposeKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ─── Right Panel: Thread View ─── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <span class="author">@_threadRootMessage.Author</span>
                <p>@_threadRootMessage.Content</p>
            </div>

            <div class="thread-replies" @ref="_threadListRef">
                @if (_threadMessages is not null)
                {
                    @foreach (var reply in _threadMessages)
                    {
                        <div class="message-bubble">
                            <div class="message-meta">
                                <span class="author">@reply.Author</span>
                                <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>

                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reactions-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => AddReactionAsync(reply.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="compose-area">
                <textarea @bind="_replyText" @bind:event="oninput"
                          placeholder="Reply…"
                          @onkeydown="OnReplyKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendReplyAsync" disabled="@string.IsNullOrWhiteSpace(_replyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    // Data
    private List<Channel>? _channels;
    private List<Message>? _messages;
    private List<Message>? _threadMessages;
    private List<ThreadSummary>? _threadSummaries;
    private Channel? _activeChannel;
    private int? _activeChannelId;
    private int _skip;
    private bool _allMessagesLoaded;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;

    // UI state
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;
    private string _newMessageText = "";
    private string _replyText = "";
    private bool _loadingOlder;

    // Element references
    private ElementReference _messageListRef;
    private ElementReference _threadListRef;
    private IJSObjectReference? _jsModule;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-354b686039354c5582e5a0a2c727e858/Components/Pages/Chat.razor.js");
        }
    }

    // ─── Channel Selection ───
    private async Task SelectChannelAsync(int channelId)
    {
        if (_activeChannelId == channelId) return;

        _activeChannelId = channelId;
        _activeChannel = _channels?.FirstOrDefault(c => c.Id == channelId);
        _skip = 0;
        _allMessagesLoaded = false;
        _messages = null;
        _threadSummaries = null;
        _emojiPickerMessageId = null;
        CloseThread();

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = loaded;
        _skip = loaded.Count;
        if (loaded.Count < PageSize) _allMessagesLoaded = true;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);
        // Update the unread count in the local channel list
        if (_channels is not null)
        {
            var idx = _channels.FindIndex(c => c.Id == channelId);
            if (idx >= 0)
                _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }

        StateHasChanged();
        await ScrollToBottomAsync();
    }

    // ─── Scroll-to-top pagination ───
    private async Task OnMessageListScroll()
    {
        if (_loadingOlder || _allMessagesLoaded || _messages is null || _activeChannelId is null || _jsModule is null)
            return;

        var scrollTop = await _jsModule.InvokeAsync<double>("getScrollTop", _messageListRef);
        if (scrollTop > 50) return;

        _loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
        if (older.Count < PageSize) _allMessagesLoaded = true;

        _messages.InsertRange(0, older);
        _skip += older.Count;
        BuildThreadSummaries();
        _loadingOlder = false;
    }

    // ─── Send message ───
    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
        _messages ??= new();
        _messages.Add(sent);
        _newMessageText = "";
        StateHasChanged();
        await ScrollToBottomAsync();
    }

    private async Task OnComposeKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
            await SendMessageAsync();
    }

    // ─── Thread ───
    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadOpen = true;
        _replyText = "";

        _threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = null;
        _replyText = "";
    }

    private async Task SendReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_replyText) || _threadRootMessage is null || _activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _replyText.Trim(), _threadRootMessage.Id);
        _threadMessages ??= new();
        _threadMessages.Add(reply);
        _replyText = "";

        // Update thread summary count
        BuildThreadSummaries();
    }

    private async Task OnReplyKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
            await SendReplyAsync();
    }

    // ─── Reactions ───
    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task PickEmojiAsync(int messageId, string emoji)
    {
        _emojiPickerMessageId = null;
        await AddReactionAsync(messageId, emoji);
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);

        // Optimistic update in the local message list
        UpdateReactionLocally(_messages, messageId, emoji);
        UpdateReactionLocally(_threadMessages, messageId, emoji);
    }

    private static void UpdateReactionLocally(List<Message>? messages, int messageId, string emoji)
    {
        if (messages is null) return;
        var idx = messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = messages[idx];
        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, new List<string> { "You" }));
        }
    }

    // ─── Thread summaries (built from loaded messages) ───
    private void BuildThreadSummaries()
    {
        if (_messages is null) { _threadSummaries = null; return; }

        var replies = _messages.Where(m => m.ReplyToId is not null).ToList();
        _threadSummaries = replies
            .GroupBy(m => m.ReplyToId!.Value)
            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)))
            .ToList();
    }

    // ─── Helpers ───
    private async Task ScrollToBottomAsync()
    {
        if (_jsModule is not null)
        {
            try { await _jsModule.InvokeVoidAsync("scrollToBottom", _messageListRef); }
            catch (JSException) { }
        }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string Truncate(string text, int maxLen) =>
        text.Length <= maxLen ? text : text[..(maxLen - 1)] + "…";

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            try { await _jsModule.DisposeAsync(); }
            catch (JSDisconnectedException) { }
        }
    }
}

